import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

const CATEGORIES = ['Technology', 'Arts', 'Sports', 'Academic', 'Cultural', 'Business', 'Science', 'Social', 'Other'];

export default function CommunityAdminProfile() {
  const [community, setCommunity] = useState(null);
  const [form, setForm] = useState({});
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    api.get('/communities/my/profile').then(res => {
      const c = res.data.data;
      setCommunity(c);
      setForm({ name: c.name, description: c.description, category: c.category, logo: c.logo || '', coverImage: c.coverImage || '', socialLinks: c.socialLinks || {} });
    }).catch(() => toast.error('Failed to load profile')).finally(() => setLoading(false));
  }, []);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));
  const setSocial = (k, v) => setForm(p => ({ ...p, socialLinks: { ...p.socialLinks, [k]: v } }));

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await api.put(`/communities/${community._id}`, form);
      toast.success('Community profile updated!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to update');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className="loading-screen"><div className="spinner" /></div>;

  return (
    <div className="page-wrapper">
      <div className="container" style={{ maxWidth: 720 }}>
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>COMMUNITY <span className="gradient-text">PROFILE</span></h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>Edit your community information</p>
            </div>
            <Link to="/community-admin" className="btn btn-outline">← Dashboard</Link>
          </div>
        </div>

        {/* Status banner */}
        {community?.status !== 'approved' && (
          <div className={`alert alert-${community?.status === 'pending' ? 'warning' : 'danger'}`} style={{ marginBottom: 24 }}>
            {community?.status === 'pending' ? '⏳ Your community is pending System Admin approval.' : '❌ Your community was rejected.'}
          </div>
        )}

        <div className="card" style={{ marginBottom: 28 }}>
          {/* Preview */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 16, marginBottom: 24, padding: '16px 20px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)' }}>
            <div className="avatar avatar-xl" style={{ borderRadius: 14, background: 'linear-gradient(135deg, var(--purple-primary), var(--blue-accent))' }}>
              {form.name?.charAt(0)}
            </div>
            <div>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem' }}>{form.name}</div>
              <div style={{ display: 'flex', gap: 8, marginTop: 6 }}>
                <span className={`badge badge-${community?.status}`}>{community?.status}</span>
                <span className={`badge badge-${form.category?.toLowerCase()}`}>{form.category}</span>
              </div>
            </div>
          </div>

          <form onSubmit={handleSave}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group">
                <label className="form-label">Community Name *</label>
                <input className="form-control" value={form.name || ''} onChange={e => set('name', e.target.value)} required />
              </div>
              <div className="form-group">
                <label className="form-label">Category *</label>
                <select className="form-control" value={form.category || ''} onChange={e => set('category', e.target.value)}>
                  {CATEGORIES.map(c => <option key={c}>{c}</option>)}
                </select>
              </div>
            </div>

            <div className="form-group">
              <label className="form-label">Description *</label>
              <textarea className="form-control" rows={4} value={form.description || ''} onChange={e => set('description', e.target.value)} required style={{ resize: 'vertical' }} />
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
              <div className="form-group">
                <label className="form-label">Logo URL</label>
                <input className="form-control" value={form.logo || ''} onChange={e => set('logo', e.target.value)} placeholder="https://..." />
              </div>
              <div className="form-group">
                <label className="form-label">Cover Image URL</label>
                <input className="form-control" value={form.coverImage || ''} onChange={e => set('coverImage', e.target.value)} placeholder="https://..." />
              </div>
            </div>

            <div style={{ marginBottom: 20 }}>
              <label className="form-label" style={{ marginBottom: 12 }}>Social Links</label>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
                {['facebook', 'instagram', 'twitter', 'website'].map(s => (
                  <div key={s}>
                    <label className="form-label" style={{ fontSize: '0.7rem', textTransform: 'capitalize' }}>{s}</label>
                    <input className="form-control" value={form.socialLinks?.[s] || ''} onChange={e => setSocial(s, e.target.value)} placeholder={`${s} URL`} />
                  </div>
                ))}
              </div>
            </div>

            <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center' }} disabled={saving}>
              {saving ? 'Saving...' : 'Save Changes'}
            </button>
          </form>
        </div>

        {/* Community info */}
        <div className="card">
          <h4 style={{ fontFamily: 'var(--font-display)', marginBottom: 16, fontSize: '1rem' }}>COMMUNITY STATS</h4>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 16 }}>
            {[
              { label: 'Members', value: community?.members?.length || 0 },
              { label: 'Events', value: community?.events?.length || 0 },
              { label: 'Created', value: new Date(community?.createdAt).toLocaleDateString() },
            ].map((s, i) => (
              <div key={i} style={{ textAlign: 'center', padding: 16, background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)' }}>
                <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem', color: 'var(--purple-light)' }}>{s.value}</div>
                <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginTop: 4 }}>{s.label}</div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
